package server

import (
	"net/http"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"testing"

	"github.com/go-chi/chi/v5"
)

// routeTableGoldenPath is the golden snapshot of the full method+path route
// table. It is regenerated by running the test with UPDATE_ROUTE_TABLE=1.
var routeTableGoldenPath = filepath.Join("testdata", "route_table.golden")

// collectRouteTable walks the fully-wired router and returns the sorted set of
// "METHOD path" lines, with chi mount/param artifacts normalized away.
func collectRouteTable(t *testing.T, router chi.Routes) []string {
	t.Helper()
	seen := make(map[string]struct{})
	if err := chi.Walk(router, func(method string, route string, _ http.Handler, _ ...func(http.Handler) http.Handler) error {
		seen[method+" "+normalizeRoutePattern(route)] = struct{}{}
		return nil
	}); err != nil {
		t.Fatalf("walk router: %v", err)
	}
	lines := make([]string, 0, len(seen))
	for line := range seen {
		lines = append(lines, line)
	}
	sort.Strings(lines)
	return lines
}

// TestRouteTableMatchesGolden snapshots the full sorted method+path route table
// into testdata/route_table.golden and fails on drift. This makes a future
// routes.go split provably behaviour-preserving: as long as the same set of
// routes is registered, this test stays green. To intentionally change the
// route surface, regenerate with: UPDATE_ROUTE_TABLE=1 go test ./internal/server/ -run RouteTable
func TestRouteTableMatchesGolden(t *testing.T) {
	router, _ := newRouteSecurityRouter(t)
	lines := collectRouteTable(t, router)
	got := strings.Join(lines, "\n") + "\n"

	if os.Getenv("UPDATE_ROUTE_TABLE") == "1" {
		if err := os.MkdirAll(filepath.Dir(routeTableGoldenPath), 0o755); err != nil {
			t.Fatalf("create testdata dir: %v", err)
		}
		if err := os.WriteFile(routeTableGoldenPath, []byte(got), 0o644); err != nil {
			t.Fatalf("write golden route table: %v", err)
		}
		t.Logf("wrote %d routes to %s", len(lines), routeTableGoldenPath)
		return
	}

	wantBytes, err := os.ReadFile(routeTableGoldenPath)
	if err != nil {
		t.Fatalf("read golden route table (regenerate with UPDATE_ROUTE_TABLE=1): %v", err)
	}
	want := string(wantBytes)
	if got == want {
		return
	}

	wantLines := splitNonEmpty(want)
	wantSet := make(map[string]struct{}, len(wantLines))
	for _, line := range wantLines {
		wantSet[line] = struct{}{}
	}
	gotSet := make(map[string]struct{}, len(lines))
	for _, line := range lines {
		gotSet[line] = struct{}{}
	}
	var added, removed []string
	for _, line := range lines {
		if _, ok := wantSet[line]; !ok {
			added = append(added, "+ "+line)
		}
	}
	for _, line := range wantLines {
		if _, ok := gotSet[line]; !ok {
			removed = append(removed, "- "+line)
		}
	}
	diff := append(removed, added...)
	sort.Strings(diff)
	t.Fatalf("route table drifted from golden (%d routes, golden has %d); "+
		"if intentional, regenerate with UPDATE_ROUTE_TABLE=1 go test ./internal/server/ -run RouteTable\n%s",
		len(lines), len(wantLines), strings.Join(diff, "\n"))
}

func splitNonEmpty(s string) []string {
	var out []string
	for _, line := range strings.Split(s, "\n") {
		if strings.TrimSpace(line) == "" {
			continue
		}
		out = append(out, line)
	}
	return out
}
